<template>
  <div>
    <el-dialog v-bind="$attrs" v-on="$listeners" :visible.sync="showDialog" @open="onOpen"
               @close="onClose" title="上传三方协议">
      <el-row :gutter="15">
        <el-form ref="elForm" :model="user"  size="medium" label-width="80px">
          <el-col :span="24">
            <el-form-item label="三方协议">
              <input type="file" ref="file2" name="check_img_url" @change="tirggerFile($event)"
                     aria-multiline="true" />
              <div>
                <img style="width:100px;height:100px;margin-left:105px" id="img2" src alt />
              </div>

            </el-form-item>
          </el-col>
        </el-form>
      </el-row>
      <div slot="footer">
        <el-button @click="close">取消</el-button>
        <el-button type="primary" @click="handelConfirm">确定</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>

  import ImageCropper from '../../components/ImageCropper';
  import PanThumb from '../../components/PanThumb';
  import { updateUser2 } from '../../api/users';
  import { uploadimg } from '../../api/uploadfile';
  import { getColleges } from '../../api/colleges';
  import { getMajors } from '../../api/majors';
  import { getClasses } from '../../api/classes';

  export default {
    name: 'UserEdit3',
    components: { ImageCropper, PanThumb },
    props:{
      addOrUpdateVisible:{
        type: Boolean,
        default: false
      }
    },
    data() {
      return {
        user: {
          tripartiteagreement: null,
          id: ''
        },
        imgUrl:'',
        imgName:'',
        imgtype2: '',
        imgtype: '',
        showDialog:false
      };
    },
    computed: {},
    watch: {
      addOrUpdateVisible(oldVal,newVal){
        this.showDialog = this.addOrUpdateVisible;
      }
    },
    created() {
    },
    mounted() {
    },
    methods: {
      onOpen() {
      },

      dataInit(data){
        if(data){
          this.user = data;
        }
      },

      onClose() {
        this.$refs.elForm.resetFields();
        this.$emit('changeShow', 'false');
      },
      close() {
        this.$emit('changeShow', 'false');
      },
      handelConfirm() {
        this.$refs.elForm.validate((valid) => {
          if (!valid) return;
          console.log(this.formData);
          this.updateUser();
        });
      },

      tirggerFile(event) {
        var file = event.target.files;
        var reader = new FileReader();// 读取文件
        var that = this;

        var name = file[0].name;
        var fileName = name.substring(name.lastIndexOf(".")+1).toLowerCase();
        if(fileName !="jpg" && fileName !="jpeg" && fileName !="png" && fileName !="bmp"){
          alert("图片格式不正确！");
          return;
        }
        var fileSize = file[0].size;
        var size = fileSize / 1024;
        if(size>10000){
          alert("图片不能大于10M");
          return;
        }else if(size <= 0){
          alert("图片不能小于0M");
          return;
        }

        reader.readAsDataURL(file[0]);
        reader.onload = function() {
          document.getElementById("img2").src = reader.result;
          that.imgUrl = reader.result;
        };

        if(file[0].type == 'image/jpeg'){
          this.user.tripartiteagreement = new Date().getTime()+".jpg";
          this.imgtype2 = "1";
          this.imgName = file[0].name;
          this.imgtype = file[0].type;
        }
        else if(file[0].type == 'image/png'){
          this.user.tripartiteagreement = new Date().getTime()+".png";
          this.imgtype2 = "2";
          this.imgName = file[0].name;
          this.imgtype = file[0].type;
        }
        else{
          this.user.tripartiteagreement = "";
          this.imgName = "";
          this.imgtype = "";
        }
      },

      async updateUser(){
        debugger;
        var that = this;
        const { data:res } = await updateUser2(this.user,this.user.tripartiteagreement,this.imgtype,this.imgName);
        if(res.code == 200){
          this.$notify.success({
            title:'操作成功',
            message: '修改成功'
          });
          console.log(this.imgUrl);
          if(this.imgtype == 'image/jpeg'){
            uploadimg(JSON.stringify(that.imgUrl),this.user.tripartiteagreement,this.imgtype2);
          }
          else if(this.imgtype == 'image/png'){
            uploadimg(JSON.stringify(that.imgUrl),this.user.tripartiteagreement,this.imgtype2);
          }
          else{
          }
          this.$emit('changeShow','false');
          this.user = {};
          this.$emit('getUserList');
        }else{
          return this.$message.error('修改失败:'+res.message);
        }
      }
    }
  };

</script>
<style>
  .el-upload__tip {
    line-height: 1.2;
  }

</style>
